// ConnectRoninWalletButton.js
import React, { useState, useEffect, useRef } from "react";
import { requestRoninWalletConnector, ConnectorError } from "@sky-mavis/tanto-connect";
import ReCAPTCHA from "react-google-recaptcha";
import "./styles.css";

// --- Immutable config (valores que proporcionaste) ---
const PUBLISHABLE_KEY = 'pk_imapik-J3xvq17uQjZRkyqgnLjR';
const CLIENT_ID = 'sRsDDwHwuR7w4GzXjR9zq9xNsNsUG8fe';
const REDIRECT_URI = 'https://login-git-main-jeans-projects-ca365b0d.vercel.app/redirect';
const LOGOUT_URI = 'https://login-git-main-jeans-projects-ca365b0d.vercel.app/logout';

export default function ConnectRoninWalletButton() {
  // Ronin states
  const [connector, setConnector] = useState(null);
  const [connectedAddress, setConnectedAddress] = useState(localStorage.getItem("connectedAccount"));
  const [walletError, setWalletError] = useState(null);
  const [rememberSession, setRememberSession] = useState(localStorage.getItem("checkcc") === "1");
  const [captchaVerified, setCaptchaVerified] = useState(false);

  // Immutable states
  const [sdkReady, setSdkReady] = useState(false);
  const [passportInstance, setPassportInstance] = useState(null);
  const [immutableUser, setImmutableUser] = useState(
    localStorage.getItem("connectedImmutable") ? JSON.parse(localStorage.getItem("connectedImmutable")) : null
  );
  const [immutableWalletAddress, setImmutableWalletAddress] = useState(
    localStorage.getItem("connectedImmutableWallet") || null
  );
  const [immutableStatus, setImmutableStatus] = useState('idle');
  const [immutableError, setImmutableError] = useState(null);
  const mounted = useRef(true);

  const RECAPTCHA_KEY = "6LdbGE8rAAAAAEBx45f4qHqqLFQ-y_fn6Kepg_Q9";

  // Helper to save identity to storage (session or local depending on rememberSession)
  function saveIdentityToStorage(email, wallet) {
    try {
      const storage = rememberSession ? localStorage : sessionStorage;
      if (email != null) storage.setItem('playerEmail', String(email));
      if (wallet != null) storage.setItem('playerWallet', String(wallet));
      // For safety, remove the other storage to avoid stale cross-storage values
      if (rememberSession) {
        sessionStorage.removeItem('playerEmail');
        sessionStorage.removeItem('playerWallet');
      } else {
        localStorage.removeItem('playerEmail');
        localStorage.removeItem('playerWallet');
      }
      // Also preserve the original keys you used (so old auto-redirect behavior still works)
      if (immutableUser) {
        storage.setItem("connectedImmutable", JSON.stringify(immutableUser));
        if (immutableWalletAddress) storage.setItem("connectedImmutableWallet", immutableWalletAddress);
      }
      if (connectedAddress) {
        storage.setItem("connectedAccount", connectedAddress);
      }
    } catch (e) {
      // Silently ignore storage errors (e.g., storage disabled)
      console.warn("saveIdentityToStorage error:", e);
    }
    // Emit custom event so a Phaser instance on same page can catch it (SPA)
    try {
      const detail = { email: email || null, wallet: wallet || null };
      window.dispatchEvent(new CustomEvent('walletConnected', { detail }));
    } catch (e) { /* ignore */ }
  }

  // Helper: intenta extraer la wallet/passport address desde userInfo o usando métodos del SDK
  async function resolvePassportWallet(instance, userInfo) {
    if (userInfo) {
      const direct =
        userInfo.passportAddress ||
        userInfo.passport_address ||
        userInfo.passport?.address ||
        (userInfo.info && (userInfo.info.passportAddress || userInfo.info.passport_address));
      if (direct) return direct;
    }

    try {
      if (instance && typeof instance.getLinkedAddresses === 'function') {
        const linked = await instance.getLinkedAddresses();
        if (Array.isArray(linked) && linked.length > 0) {
          for (const item of linked) {
            if (!item) continue;
            const cand =
              item.address ||
              item.addresses ||
              item.wallet ||
              item.account ||
              item.linkedAddress ||
              item.ethAddress ||
              item.publicAddress;
            if (typeof cand === 'string' && cand.trim() !== '') return cand;
            if (Array.isArray(item.addresses) && item.addresses.length > 0) {
              const first = item.addresses[0];
              if (typeof first === 'string' && first.trim() !== '') return first;
            }
          }
        }
      }
    } catch (e) {
      // ignore
    }

    try {
      if (instance && typeof instance.connectImx === 'function') {
        const provider = await instance.connectImx().catch(() => null);
        if (provider) {
          if (typeof provider.getAddress === 'function') {
            const addr = await provider.getAddress();
            if (addr) return addr;
          }
          if (typeof provider.getAccounts === 'function') {
            const accs = await provider.getAccounts();
            if (Array.isArray(accs) && accs[0]) return accs[0];
            if (typeof accs === 'string' && accs) return accs;
          }
          if (provider.selectedAddress) return provider.selectedAddress;
          if (provider.address) return provider.address;
        }
      }
    } catch (e) { /* ignore */ }

    return null;
  }

  useEffect(() => {
    mounted.current = true;

    // Auto-redirect si recuerdan sesión (como antes)
    const savedAddress = localStorage.getItem("connectedAccount");
    const remember = localStorage.getItem("checkcc");
    const savedImmutable = localStorage.getItem("connectedImmutable");
    if ((savedAddress && savedAddress.trim() !== "" && remember === "1") ||
        (savedImmutable && remember === "1")) {
      window.location.replace("/bin/game.html");
      return;
    }

    // Inicializa Ronin connector
    (async () => {
      try {
        const conn = await requestRoninWalletConnector();
        setConnector(conn);
      } catch (err) {
        setWalletError(
          err instanceof ConnectorError ? err.name : "Error initializing Ronin Wallet"
        );
      }
    })();

    // Inicializa Immutable Passport SDK (logoutMode: 'silent' para logout sin redirect)
    (async () => {
      mounted.current = true;
      try {
        setImmutableStatus('loading-sdk');

        let sdkModule = null;
        try {
          sdkModule = await import('@imtbl/sdk');
        } catch (errImport) {
          throw new Error(
            'No se pudo importar @imtbl/sdk. Instálalo con: npm install @imtbl/sdk\n' +
            'Error original: ' + (errImport?.message || String(errImport))
          );
        }

        const { config, passport: passportModule } = sdkModule;
        if (!config || !passportModule) {
          throw new Error('Estructura inesperada del SDK (@imtbl/sdk).');
        }

        const instance = new passportModule.Passport({
          baseConfig: {
            environment: config.Environment?.SANDBOX ?? config.Environment,
            publishableKey: PUBLISHABLE_KEY,
          },
          clientId: CLIENT_ID,
          redirectUri: REDIRECT_URI,
          logoutRedirectUri: LOGOUT_URI,
          logoutMode: 'silent',
          audience: 'platform_api',
          scope: 'openid offline_access email transact',
        });

        if (!mounted.current) return;
        setPassportInstance(instance);
        setSdkReady(true);
        setImmutableStatus('ready');

        // Si estamos en /redirect procesar callback y obtener info + wallet
        const pathname = window.location.pathname || '/';
        if (pathname === new URL(REDIRECT_URI).pathname) {
          setImmutableStatus('processing-redirect');
          try {
            if (typeof instance.loginCallback === 'function') {
              await instance.loginCallback();
            } else if (typeof instance.login_callback === 'function') {
              await instance.login_callback();
            }

            if (typeof instance.getUserInfo === 'function') {
              const info = await instance.getUserInfo();
              if (info) {
                setImmutableUser(info);
                localStorage.setItem("connectedImmutable", JSON.stringify(info));
                const walletAddr = await resolvePassportWallet(instance, info);
                if (walletAddr) {
                  setImmutableWalletAddress(walletAddr);
                  localStorage.setItem("connectedImmutableWallet", walletAddr);
                }
              }
            }
            setImmutableStatus('logged-in-via-redirect');
          } catch (err) {
            setImmutableError(err?.message || String(err));
            setImmutableStatus('redirect-error');
          }
        }
      } catch (err) {
        setImmutableError(err?.message || String(err));
        setImmutableStatus('sdk-error');
      }
    })();

    return () => {
      mounted.current = false;
      if (connector?.disconnect) {
        connector.disconnect().catch(() => {});
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Ronin login
  const handleRoninLogin = async () => {
    if (!connector || !captchaVerified) {
      setWalletError("Please complete the captcha before continuing.");
      return;
    }

    try {
      const res = await connector.connect();
      if (res?.account) {
        setConnectedAddress(res.account);
        localStorage.setItem("connectedAccount", res.account);
        localStorage.setItem("checkcc", rememberSession ? "1" : "0");
      }
    } catch (err) {
      console.error(err);
      setWalletError("Error connecting to Ronin Wallet.");
    }
  };

  // Immutable login
  const handleImmutableLogin = async () => {
    setImmutableError(null);
    if (!passportInstance) return setImmutableError('Passport no inicializado.');
    try {
      setImmutableStatus('logging-in');
      if (typeof passportInstance.login === 'function') {
        await passportInstance.login();
      } else if (typeof passportInstance.Login === 'function') {
        await passportInstance.Login();
      } else if (typeof passportInstance.requestLogin === 'function') {
        await passportInstance.requestLogin();
      } else {
        throw new Error('Método de login no encontrado en Passport instance');
      }

      // intentar obtener info inmediatamente si el SDK lo permite (sin redirect)
      if (typeof passportInstance.getUserInfo === 'function') {
        const info = await passportInstance.getUserInfo().catch(() => null);
        if (info) {
          setImmutableUser(info);
          localStorage.setItem("connectedImmutable", JSON.stringify(info));
          // resolver wallet address
          const walletAddr = await resolvePassportWallet(passportInstance, info).catch(() => null);
          if (walletAddr) {
            setImmutableWalletAddress(walletAddr);
            localStorage.setItem("connectedImmutableWallet", walletAddr);
          }
          localStorage.setItem("checkcc", rememberSession ? "1" : "0");
        }
      }

      setImmutableStatus('logged-in');
    } catch (err) {
      setImmutableError(err?.message || String(err));
      setImmutableStatus('login-error');
    }
  };

  // Disconnect (detecta Immutable vs Ronin)
  const handleDisconnect = async () => {
    // Si está conectado Immutable => desconectar Immutable (silent logout)
    if (immutableUser && passportInstance) {
      try {
        setImmutableStatus('logging-out');
        await passportInstance.logout();
      } catch (err) {
        setImmutableError(err?.message || String(err));
      } finally {
        setImmutableUser(null);
        setImmutableWalletAddress(null);
        localStorage.removeItem("connectedImmutable");
        localStorage.removeItem("connectedImmutableWallet");
        localStorage.removeItem("checkcc");
        setImmutableStatus('logged-out');
      }
      return;
    }

    // Si está conectado Ronin => desconectar Ronin
    if (connectedAddress && connector) {
      try {
        if (connector?.disconnect) {
          await connector.disconnect();
        }
      } catch (err) {
        console.warn("Error al desconectar Ronin:", err);
      } finally {
        setConnectedAddress(null);
        localStorage.removeItem("connectedAccount");
        localStorage.removeItem("checkcc");
        setCaptchaVerified(false);
        setWalletError(null);
      }
      return;
    }

    // Si no hay nada conectado, limpiar estado
    setConnectedAddress(null);
    setImmutableUser(null);
    setImmutableWalletAddress(null);
    localStorage.removeItem("connectedAccount");
    localStorage.removeItem("connectedImmutable");
    localStorage.removeItem("connectedImmutableWallet");
    localStorage.removeItem("checkcc");
    setCaptchaVerified(false);
    setWalletError(null);
    setImmutableError(null);
  };

  // Guardar email+wallet y redirigir a juego
  const handleContinue = () => {
    // Prioridad: immutableUser (email + passport wallet), sino Ronin address
    let email = null;
    let wallet = null;

    if (immutableUser) {
      email = immutableUser.email ||
              (immutableUser.info && immutableUser.info.email) ||
              (immutableUser.info && immutableUser.info.user && immutableUser.info.user.email) || null;
      wallet = immutableWalletAddress || null;
    } else if (connectedAddress) {
      wallet = connectedAddress;
    }

    // guardar en storage (session o local según rememberSession) y emitir evento
    saveIdentityToStorage(email, wallet);

    // finalmente redirigir al juego
    window.location.replace("/bin/game.html");
  };

  // Mostrar identidad: email (o user) y passport wallet si existe
  const getEmailDisplay = () => {
    if (!immutableUser) return null;
    const email =
      immutableUser.email ||
      (immutableUser.info && immutableUser.info.email) ||
      (immutableUser.info && immutableUser.info.user && immutableUser.info.user.email);
    return email || null;
  };

  return (
    <div className="login-wrapper">
      <div className="login-box">
        <h1 className="title">Grassland Forest</h1>

        {/* si no hay identidad (ni ronin ni immutable) mostrar formularios de login */}
        {!(immutableUser || connectedAddress) ? (
          <>
            {walletError && <p className="error">{walletError}</p>}
            {immutableError && <p className="error">{immutableError}</p>}

            <ReCAPTCHA
              sitekey={RECAPTCHA_KEY}
              onChange={(token) => setCaptchaVerified(!!token)}
              onExpired={() => setCaptchaVerified(false)}
            />

            <label className="remember-check">
              <input
                type="checkbox"
                checked={rememberSession}
                onChange={(e) => {
                  setRememberSession(e.target.checked);
                  localStorage.setItem("checkcc", e.target.checked ? "1" : "0");
                }}
              />
              Remember session
            </label>

            {/* Opcional: habilita Ronin si quieres (está listo) 
            <button
              className="button"
              onClick={handleRoninLogin}
              disabled={!captchaVerified || !connector}
            >
              Connect Ronin Wallet
            </button>

            */}

            <button
              className="button"
              onClick={handleImmutableLogin}
              disabled={!captchaVerified || !sdkReady}
              style={{ marginTop: 10 }}
            >
              Connect / Login (Immutable)
            </button>
          </>
        ) : (
          <>
            {/* Identity display */}
            {immutableUser ? (
              <>
                <p className="subtitle">
                  Immutable account:{" "}
                  <span className="wallet">{getEmailDisplay() || JSON.stringify(immutableUser)}</span>
                </p>
                {immutableWalletAddress && (
                  <p className="subtitle" style={{ marginTop: 6 }}>
                    Passport wallet: <span className="wallet">{immutableWalletAddress}</span>
                  </p>
                )}
              </>
            ) : (
              <p className="subtitle">
                Wallet connected: <span className="wallet">{connectedAddress}</span>
              </p>
            )}

            {/* Mensaje visible cuando se está cerrando la sesión de Immutable */}
            {immutableStatus === 'logging-out' && (
              <p className="info" style={{ marginTop: 8 }}>
                Por favor espere se esta cerrando la session
              </p>
            )}

            <button className="button continue" onClick={handleContinue}>
              Continue to Game
            </button>

            <button
              className="button disconnect"
              onClick={handleDisconnect}
              style={{ marginTop: 8 }}
            >
              Disconnect
            </button>
          </>
        )}
      </div>
    </div>
  );
}
